package main

import "fmt"

func main() {
    // ---- Basic pointers ----
    x := 42
    p := &x  // p points to x

    fmt.Println("x:", x)
    fmt.Println("p:", p)
    fmt.Println("*p:", *p)

    // ---- Changing value through pointer ----
    *p = 100
    fmt.Println("After *p = 100, x:", x)

    // ---- Pointer to struct ----
    type Player struct {
        Name   string
        Health int
    }

    hero := Player{Name: "Hero", Health: 100}
    p2 := &hero

    p2.Health = 80  // Automatic dereference
    fmt.Println("Hero health:", hero.Health)

    // ---- nil pointer ----
    var p3 *int
    if p3 == nil {
        fmt.Println("p3 is nil")
    }

    // ---- Function with pointer ----
    func double(x *int) {
        *x *= 2
    }

    y := 5
    double(&y)
    fmt.Println("y after double:", y)

    // ---- Function with pointer to struct ----
    func heal(player *Player, amount int) {
        player.Health += amount
        if player.Health > 100 {
            player.Health = 100
        }
    }

    heal(&hero, 50)
    fmt.Println("Hero after heal:", hero.Health)

    // ---- Pointer to array ----
    arr := [3]int{1, 2, 3}
    p4 := &arr
    p4[0] = 10
    fmt.Println("Array after pointer:", arr)

    // ---- No pointer arithmetic ----
    // Go doesn't allow pointer arithmetic
    // This is intentional
}

